using System.Text.Json;

namespace Azure.ResourceManager
{
    /// <summary>
    /// AOT-safe helper for serializing and deserializing <see cref="ResponseError"/>.
    /// ResponseError is an external type (Azure.Core) with an internal JsonConverter,
    /// so source generation cannot be used.
    /// </summary>
    internal static class ResponseErrorSerialization
    {
        internal static void WriteResponseError(Utf8JsonWriter writer, ResponseError error)
        {
            writer.WriteStartObject();
            if (error.Code != null)
            {
                writer.WriteString("code", error.Code);
            }
            if (error.Message != null)
            {
                writer.WriteString("message", error.Message);
            }
            if (error.Target != null)
            {
                writer.WriteString("target", error.Target);
            }
            if (error.InnerError != null)
            {
                writer.WritePropertyName("innererror");
                WriteResponseInnerError(writer, error.InnerError);
            }
            if (error.Details != null && error.Details.Count > 0)
            {
                writer.WritePropertyName("details");
                writer.WriteStartArray();
                foreach (var detail in error.Details)
                {
                    WriteResponseError(writer, detail);
                }
                writer.WriteEndArray();
            }
            writer.WriteEndObject();
        }

        private static void WriteResponseInnerError(Utf8JsonWriter writer, ResponseInnerError innerError)
        {
            writer.WriteStartObject();
            if (innerError.Code != null)
            {
                writer.WriteString("code", innerError.Code);
            }
            if (innerError.InnerError != null)
            {
                writer.WritePropertyName("innererror");
                WriteResponseInnerError(writer, innerError.InnerError);
            }
            writer.WriteEndObject();
        }

        internal static ResponseError DeserializeResponseError(JsonElement element)
        {
            if (element.ValueKind == JsonValueKind.Null)
            {
                return null;
            }

            string code = null;
            string message = null;
            string target = null;
            ResponseInnerError innerError = null;
            List<ResponseError> details = null;

            foreach (var property in element.EnumerateObject())
            {
                if (property.NameEquals("code"))
                {
                    code = property.Value.GetString();
                }
                else if (property.NameEquals("message"))
                {
                    message = property.Value.GetString();
                }
                else if (property.NameEquals("target"))
                {
                    target = property.Value.GetString();
                }
                else if (property.NameEquals("innererror"))
                {
                    innerError = DeserializeResponseInnerError(property.Value);
                }
                else if (property.NameEquals("details"))
                {
                    details = new List<ResponseError>();
                    foreach (var item in property.Value.EnumerateArray())
                    {
                        details.Add(DeserializeResponseError(item));
                    }
                }
            }

            return new ResponseError(code, message, target, default, innerError, details);
        }

        private static ResponseInnerError DeserializeResponseInnerError(JsonElement element)
        {
            if (element.ValueKind == JsonValueKind.Null)
            {
                return null;
            }

            string code = null;
            ResponseInnerError innerError = null;

            foreach (var property in element.EnumerateObject())
            {
                if (property.NameEquals("code"))
                {
                    code = property.Value.GetString();
                }
                else if (property.NameEquals("innererror"))
